-// POSIX fnmatch flag constants. Bit values must match glibc's
-// /usr/include/fnmatch.h exactly — they're part of the libc ABI and
-// any caller that includes the system header passes those bits
-// directly. Found by the fuzz_pattern_match differential harness
-// (PATHNAME and NOESCAPE were previously swapped — bd-m40be).
-const FNM_PATHNAME: c_int = 1 << 0;
-const FNM_NOESCAPE: c_int = 1 << 1;
-const FNM_PERIOD: c_int = 1 << 2;
-const FNM_CASEFOLD: c_int = 1 << 4; // GNU extension
 const FNM_NOMATCH: c_int = 1;

-/// Native POSIX `fnmatch` — match a filename against a shell wildcard pattern.
+/// POSIX `fnmatch` — match a filename against a shell wildcard pattern.
 ///
-/// Supports `*`, `?`, `[...]` bracket expressions with ranges and negation.
-/// Flags: `FNM_NOESCAPE`, `FNM_PATHNAME`, `FNM_PERIOD`, `FNM_CASEFOLD`.
+/// Thin shim over [`frankenlibc_core::string::fnmatch::fnmatch_match`]
+/// (bd-fnm-2, epic bd-fnm-epic). The engine itself lives in core as a
+/// pure-safe pattern matcher operating on byte slices; this layer
+/// handles raw-pointer / NUL-terminated C string adaptation.
 #[cfg_attr(not(debug_assertions), unsafe(no_mangle))]
 pub unsafe extern "C" fn fnmatch(
     pattern: *const c_char,
@@ -5181,328 +5174,20 @@ pub unsafe extern "C" fn fnmatch(
     if pattern.is_null() || string.is_null() {
         return FNM_NOMATCH;
     }
-
-    let pat = pattern as *const u8;
-    let str_ = string as *const u8;
-
-    if unsafe { fnmatch_impl(pat, 0, str_, 0, flags, true) } {
+    // Adapt NUL-terminated C strings to byte slices.
+    let pat_bytes = unsafe { core::ffi::CStr::from_ptr(pattern) }.to_bytes();
+    let str_bytes = unsafe { core::ffi::CStr::from_ptr(string) }.to_bytes();
+    let core_flags = frankenlibc_core::string::fnmatch::FnmatchFlags::from_bits(flags as u32);
+    if frankenlibc_core::string::fnmatch::fnmatch_match(pat_bytes, str_bytes, core_flags) {
         0
     } else {
         FNM_NOMATCH
     }
 }

-/// Outcome of pre-classifying a `[...]` bracket expression at `pat[pi]`.
-/// Mirrors glibc's observed behavior: a closed bracket parses normally;
-/// an unterminated bracket whose final content byte is `-` (an
-/// incomplete range) yields no-match; any other unterminated bracket is
-/// treated as a literal `[` followed by literal characters.
-enum BracketShape {
-    Terminated,
-    LiteralFallback,
-    Invalid,
-}
-
-/// Walk the bracket starting at `pat[pi]` (must point at `[`) without
-/// consuming any input, returning whether it's terminated, an
-/// incomplete range, or harmlessly unterminated. Used so the main
-/// matcher can choose between bracket parsing, literal `[` matching,
-/// and outright failure.
-unsafe fn classify_bracket(pat: *const u8, pi: usize) -> BracketShape {
-    let mut scan = pi + 1; // skip the opening '['
-    if unsafe { *pat.add(scan) } == b'!' || unsafe { *pat.add(scan) } == b'^' {
-        scan += 1;
-    }
-    let mut content_count = 0usize;
-    let mut last_was_dash = false;
-    loop {
-        let bc = unsafe { *pat.add(scan) };
-        if bc == 0 {
-            // Hit NUL with no closing ']'. If the last content byte
-            // was a `-` and at least one earlier content byte preceded
-            // it, glibc reports that as an incomplete range and the
-            // whole match fails; otherwise the `[...` becomes literal.
-            if last_was_dash && content_count > 1 {
-                return BracketShape::Invalid;
-            }
-            return BracketShape::LiteralFallback;
-        }
-        // POSIX: a `]` as the first content byte (after optional !/^)
-        // is literal, not a closer — that's the `content_count > 0`
-        // gate.
-        if bc == b']' && content_count > 0 {
-            return BracketShape::Terminated;
-        }
-        last_was_dash = bc == b'-';
-        content_count += 1;
-        scan += 1;
-    }
-}
-
-/// Recursive fnmatch implementation operating on byte pointers + offsets.
-unsafe fn fnmatch_impl(
-    pat: *const u8,
-    mut pi: usize,
-    str_: *const u8,
-    mut si: usize,
-    flags: c_int,
-    at_start: bool,
-) -> bool {
-    let pathname = flags & FNM_PATHNAME != 0;
-    let period = flags & FNM_PERIOD != 0;
-    let noescape = flags & FNM_NOESCAPE != 0;
-    let casefold = flags & FNM_CASEFOLD != 0;
-
-    // Track whether the next string character is still "at the start"
-    // for leading-period purposes. As soon as we consume a string
-    // character, subsequent `?`/`*`/bracket/literal matches are no
-    // longer at-start (bd-64uch found via fuzz_pattern_match).
-    let mut at_start = at_start;
-
-    loop {
-        let pc = unsafe { *pat.add(pi) };
-        let sc = unsafe { *str_.add(si) };
-
-        if pc == 0 {
-            return sc == 0;
-        }
-
-        match pc {
-            b'?' => {
-                if sc == 0 {
-                    return false;
-                }
-                if pathname && sc == b'/' {
-                    return false;
-                }
-                if period
-                    && sc == b'.'
-                    && (at_start || (pathname && si > 0 && unsafe { *str_.add(si - 1) } == b'/'))
-                {
-                    return false;
-                }
-                pi += 1;
-                si += 1;
-                at_start = false;
-            }
-            b'*' => {
-                // Skip consecutive *'s
-                while unsafe { *pat.add(pi) } == b'*' {
-                    pi += 1;
-                }
-
-                // Leading period check: * doesn't match leading .
-                if period
-                    && sc == b'.'
-                    && (at_start || (pathname && si > 0 && unsafe { *str_.add(si - 1) } == b'/'))
-                {
-                    return false;
-                }
-
-                // If pattern is exhausted after *, match rest of string
-                if unsafe { *pat.add(pi) } == 0 {
-                    if pathname {
-                        let mut j = si;
-                        while unsafe { *str_.add(j) } != 0 {
-                            if unsafe { *str_.add(j) } == b'/' {
-                                return false;
-                            }
-                            j += 1;
-                        }
-                    }
-                    return true;
-                }
-
-                // Try matching * against increasingly longer prefixes
-                let mut j = si;
-                loop {
-                    let ch = unsafe { *str_.add(j) };
-                    if unsafe { fnmatch_impl(pat, pi, str_, j, flags, false) } {
-                        return true;
-                    }
-                    if ch == 0 {
-                        break;
-                    }
-                    if pathname && ch == b'/' {
-                        break;
-                    }
-                    j += 1;
-                }
-                return false;
-            }
-            b'[' => {
-                // POSIX leaves an unterminated bracket expression
-                // implementation-defined; glibc has a more nuanced
-                // rule than "always literal" — see classify_bracket
-                // (bd-64uch).
-                match unsafe { classify_bracket(pat, pi) } {
-                    BracketShape::Invalid => return false,
-                    BracketShape::LiteralFallback => {
-                        if sc == 0
-                            || (pathname && sc == b'/')
-                            || (period
-                                && sc == b'.'
-                                && (at_start
-                                    || (pathname
-                                        && si > 0
-                                        && unsafe { *str_.add(si - 1) } == b'/')))
-                        {
-                            return false;
-                        }
-                        let eq = if casefold {
-                            b'['.eq_ignore_ascii_case(&sc)
-                        } else {
-                            sc == b'['
-                        };
-                        if !eq {
-                            return false;
-                        }
-                        pi += 1;
-                        si += 1;
-                        at_start = false;
-                        continue;
-                    }
-                    BracketShape::Terminated => {}
-                }
-
-                if sc == 0 || (pathname && sc == b'/') {
-                    return false;
-                }
-                if period
-                    && sc == b'.'
-                    && (at_start || (pathname && si > 0 && unsafe { *str_.add(si - 1) } == b'/'))
-                {
-                    return false;
-                }
-
-                pi += 1; // skip '['
-                let negated = unsafe { *pat.add(pi) } == b'!' || unsafe { *pat.add(pi) } == b'^';
-                if negated {
-                    pi += 1;
-                }
-
-                let mut matched = false;
-                let mut first = true;
-                loop {
-                    let bc = unsafe { *pat.add(pi) };
-                    if bc == 0 {
-                        return false; // unterminated bracket
-                    }
-                    if bc == b']' && !first {
-                        break;
-                    }
-                    first = false;
-
-                    let mut low = bc;
-                    pi += 1;
-
-                    // Handle escape in bracket
-                    if low == b'\\' && !noescape {
-                        low = unsafe { *pat.add(pi) };
-                        if low == 0 {
-                            return false;
-                        }
-                        pi += 1;
-                    }
-
-                    // Check for range (a-z)
-                    if unsafe { *pat.add(pi) } == b'-'
-                        && unsafe { *pat.add(pi + 1) } != b']'
-                        && unsafe { *pat.add(pi + 1) } != 0
-                    {
-                        pi += 1; // skip '-'
-                        let mut high = unsafe { *pat.add(pi) };
-                        if high == b'\\' && !noescape {
-                            pi += 1;
-                            high = unsafe { *pat.add(pi) };
-                            if high == 0 {
-                                return false;
-                            }
-                        }
-                        pi += 1;
-
-                        let test_ch = if casefold {
-                            sc.to_ascii_lowercase()
-                        } else {
-                            sc
-                        };
-                        let low_cmp = if casefold {
-                            low.to_ascii_lowercase()
-                        } else {
-                            low
-                        };
-                        let high_cmp = if casefold {
-                            high.to_ascii_lowercase()
-                        } else {
-                            high
-                        };
-                        if test_ch >= low_cmp && test_ch <= high_cmp {
-                            matched = true;
-                        }
-                    } else {
-                        let test_ch = if casefold {
-                            sc.to_ascii_lowercase()
-                        } else {
-                            sc
-                        };
-                        let low_cmp = if casefold {
-                            low.to_ascii_lowercase()
-                        } else {
-                            low
-                        };
-                        if test_ch == low_cmp {
-                            matched = true;
-                        }
-                    }
-                }
-                pi += 1; // skip ']'
-
-                if negated {
-                    matched = !matched;
-                }
-                if !matched {
-                    return false;
-                }
-                si += 1;
-                at_start = false;
-            }
-            b'\\' if !noescape => {
-                pi += 1;
-                let escaped = unsafe { *pat.add(pi) };
-                if escaped == 0 || sc == 0 {
-                    return false;
-                }
-                let eq = if casefold {
-                    escaped.eq_ignore_ascii_case(&sc)
-                } else {
-                    escaped == sc
-                };
-                if !eq {
-                    return false;
-                }
-                pi += 1;
-                si += 1;
-                at_start = false;
-            }
-            _ => {
-                if sc == 0 {
-                    return false;
-                }
-                let eq = if casefold {
-                    pc.eq_ignore_ascii_case(&sc)
-                } else {
-                    pc == sc
-                };
-                if !eq {
-                    return false;
-                }
-                pi += 1;
-                si += 1;
-                at_start = false;
-            }
-        }
-    }
-}
+// (BracketShape, classify_bracket, fnmatch_impl moved into
+// frankenlibc-core/src/string/fnmatch.rs by bd-fnm-1; the legacy
+// inline implementation that lived here was deleted by bd-fnm-2.)

